import { Component, EventEmitter, Input, Output } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { SearchHit } from '../../core/models';

/**
 * Name + content search panel (`?panel=search`). Emits `(search)` when the user
 * submits a query; the editor shell runs the search (mockup: local; live:
 * GET /workspaces/:id/search) and passes results back via `results`. Clicking a
 * hit emits `(openHit)` so the shell opens that file at the first match.
 */
@Component({
  selector: 'app-search-panel',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './search-panel.component.html',
  styleUrl: './search-panel.component.css',
})
export class SearchPanelComponent {
  @Input() term = '';
  @Input() results: SearchHit[] = [];
  @Input() searched = false;

  @Output() search = new EventEmitter<string>();
  @Output() openHit = new EventEmitter<SearchHit>();
  @Output() closePanel = new EventEmitter<void>();

  submit(): void {
    this.search.emit(this.term.trim());
  }
}
