import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { FileContent, Revision, SearchHit, TreeNode } from '../../core/models';
import { CodeEditorComponent } from './code-editor.component';
import { CreatePayload, FileTreeComponent, MovePayload } from './file-tree.component';
import { SearchPanelComponent } from './search-panel.component';
import { RevisionHistoryComponent } from './revision-history.component';

interface Tab {
  id: string;
  name: string;
}

const AUTOSAVE_KEY = 'codedeck.autosave';

/**
 * CodeDeck editor shell — the heart of the app. Owns:
 *  - the workspace file tree (create/rename/delete/move),
 *  - the open-tabs signal synced to `?file=<nodeId>`,
 *  - the active editor buffer with dirty tracking + Ctrl/⌘+S save,
 *  - an autosave toggle persisted in localStorage,
 *  - side panels (search / history) synced to `?panel=`, plus `?q=` and `?rev=`.
 *
 * Backend-provided data lives in `signal<T[]>` per the data contract (tree,
 * fileContents, revisions); the service_agent stage clears these and wires the
 * ApiService node/content/revision/search methods.
 */
@Component({
  selector: 'app-workspace-editor',
  standalone: true,
  imports: [
    CommonModule,
    RouterLink,
    CodeEditorComponent,
    FileTreeComponent,
    SearchPanelComponent,
    RevisionHistoryComponent,
  ],
  templateUrl: './workspace-editor.component.html',
  styleUrl: './workspace-editor.component.css',
})
export class WorkspaceEditorComponent implements OnInit {
  readonly workspaceId = signal<string>('');
  readonly workspaceName = signal<string>('Sample Project');
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  // ---- Backend data (mock; cleared + wired by service_agent) ----
  readonly tree = signal<TreeNode[]>([
    { id: 'n-readme', workspaceId: 'ws-1', parentId: null, type: 'file', name: 'README.md' },
    {
      id: 'n-src',
      workspaceId: 'ws-1',
      parentId: null,
      type: 'folder',
      name: 'src',
      children: [
        { id: 'n-index', workspaceId: 'ws-1', parentId: 'n-src', type: 'file', name: 'index.js' },
        { id: 'n-style', workspaceId: 'ws-1', parentId: 'n-src', type: 'file', name: 'style.css' },
      ],
    },
    { id: 'n-pkg', workspaceId: 'ws-1', parentId: null, type: 'file', name: 'package.json' },
  ]);

  readonly fileContents = signal<FileContent[]>([
    {
      nodeId: 'n-readme',
      content: '# Sample Project\n\nA CodeDeck demo workspace.\n\n- Edit files in the tabbed editor\n- Save with Ctrl/Cmd+S\n- Browse revision history\n',
    },
    {
      nodeId: 'n-index',
      content:
        "function greet(name) {\n  return `Hello, ${name}!`;\n}\n\nconsole.log(greet('CodeDeck'));\n",
    },
    {
      nodeId: 'n-style',
      content: 'body {\n  margin: 0;\n  font-family: system-ui, sans-serif;\n  color: #1a1730;\n}\n',
    },
    {
      nodeId: 'n-pkg',
      content: '{\n  "name": "sample-project",\n  "version": "1.0.0",\n  "type": "module"\n}\n',
    },
  ]);

  readonly revisions = signal<Revision[]>([
    { id: 'r-3', nodeId: 'n-index', content: "function greet(name) {\n  return `Hello, ${name}!`;\n}\n", savedAt: '2026-07-11T14:20:00.000Z' },
    { id: 'r-2', nodeId: 'n-index', content: "function greet(n) {\n  return 'Hello ' + n;\n}\n", savedAt: '2026-07-11T11:02:00.000Z' },
    { id: 'r-1', nodeId: 'n-index', content: "function greet() {\n  return 'Hello';\n}\n", savedAt: '2026-07-10T16:45:00.000Z' },
  ]);

  // ---- Editor UI state ----
  readonly openTabs = signal<Tab[]>([]);
  readonly activeId = signal<string | null>(null);
  readonly dirtyIds = signal<string[]>([]);
  readonly panel = signal<'search' | 'history' | null>(null);
  readonly autosave = signal<boolean>(false);

  // ---- Search state ----
  readonly searchTerm = signal<string>('');
  readonly searchResults = signal<SearchHit[]>([]);
  readonly searched = signal<boolean>(false);
  readonly activeRevId = signal<string | null>(null);

  // ---- Mobile: which pane is visible ----
  readonly treeOpen = signal<boolean>(false);

  private autosaveTimer: ReturnType<typeof setTimeout> | null = null;

  readonly activeNode = computed<TreeNode | null>(() =>
    this.activeId() ? this.findNode(this.tree(), this.activeId()!) : null,
  );
  readonly activeContent = computed<string>(() => {
    const id = this.activeId();
    if (!id) return '';
    return this.fileContents().find((f) => f.nodeId === id)?.content ?? '';
  });
  readonly activeRevisions = computed<Revision[]>(() => {
    const id = this.activeId();
    return id ? this.revisions().filter((r) => r.nodeId === id) : [];
  });

  constructor(private route: ActivatedRoute, private router: Router) {}

  ngOnInit(): void {
    this.workspaceId.set(this.route.snapshot.paramMap.get('id') || 'ws-1');
    this.autosave.set(localStorage.getItem(AUTOSAVE_KEY) === 'true');

    // Restore deep-link state from query params.
    const qp = this.route.snapshot.queryParamMap;
    const file = qp.get('file');
    const panel = qp.get('panel');
    const q = qp.get('q');
    const rev = qp.get('rev');

    if (file && this.findNode(this.tree(), file)) {
      this.openFile(file, false);
    }
    if (panel === 'search' || panel === 'history') {
      this.panel.set(panel);
    }
    if (q) {
      this.searchTerm.set(q);
      this.runSearch(q, false);
    }
    if (rev) {
      this.activeRevId.set(rev);
    }
  }

  // ---- Tabs ----
  isDirty(id: string): boolean {
    return this.dirtyIds().includes(id);
  }

  openFile(id: string, sync = true): void {
    const node = this.findNode(this.tree(), id);
    if (!node || node.type !== 'file') return;
    if (!this.openTabs().some((t) => t.id === id)) {
      this.openTabs.update((tabs) => [...tabs, { id, name: node.name }]);
    }
    this.activeId.set(id);
    this.treeOpen.set(false);
    if (sync) this.syncUrl();
  }

  closeTab(id: string, event?: Event): void {
    event?.stopPropagation();
    const tabs = this.openTabs().filter((t) => t.id !== id);
    this.openTabs.set(tabs);
    this.dirtyIds.update((d) => d.filter((x) => x !== id));
    if (this.activeId() === id) {
      this.activeId.set(tabs.length ? tabs[tabs.length - 1].id : null);
    }
    this.syncUrl();
  }

  selectTab(id: string): void {
    this.activeId.set(id);
    this.syncUrl();
  }

  // ---- Editing / saving ----
  onContentChange(text: string): void {
    const id = this.activeId();
    if (!id) return;
    this.setContent(id, text);
    if (!this.isDirty(id)) this.dirtyIds.update((d) => [...d, id]);

    if (this.autosave()) {
      if (this.autosaveTimer) clearTimeout(this.autosaveTimer);
      this.autosaveTimer = setTimeout(() => this.saveActive(), 800);
    }
  }

  saveActive(): void {
    const id = this.activeId();
    if (!id || !this.isDirty(id)) return;
    // Push a new revision (newest first), prune to 10 for this file.
    const content = this.activeContent();
    const newRev: Revision = {
      id: `r-${Math.round(performance.now())}`,
      nodeId: id,
      content,
      savedAt: new Date(2026, 6, 12, 12, 0, 0).toISOString(),
    };
    const others = this.revisions().filter((r) => r.nodeId !== id);
    const mine = [newRev, ...this.revisions().filter((r) => r.nodeId === id)].slice(0, 10);
    this.revisions.set([...mine, ...others]);
    this.dirtyIds.update((d) => d.filter((x) => x !== id));
  }

  toggleAutosave(): void {
    const next = !this.autosave();
    this.autosave.set(next);
    localStorage.setItem(AUTOSAVE_KEY, String(next));
    if (next) this.saveActive();
  }

  // ---- Panels ----
  togglePanel(p: 'search' | 'history'): void {
    this.panel.set(this.panel() === p ? null : p);
    this.syncUrl();
  }
  closePanel(): void {
    this.panel.set(null);
    this.syncUrl();
  }

  runSearch(term: string, sync = true): void {
    this.searchTerm.set(term);
    this.searched.set(true);
    if (!term) {
      this.searchResults.set([]);
      if (sync) this.syncUrl();
      return;
    }
    const lower = term.toLowerCase();
    const hits: SearchHit[] = [];
    const paths = this.buildPaths();
    for (const node of this.flatten(this.tree())) {
      if (node.type !== 'file') continue;
      const path = paths.get(node.id) || '/' + node.name;
      const nameMatch = node.name.toLowerCase().includes(lower);
      const content = this.fileContents().find((f) => f.nodeId === node.id)?.content ?? '';
      const lines = content.split('\n');
      let firstLine = 0;
      let snippet: string | null = null;
      for (let i = 0; i < lines.length; i++) {
        if (lines[i].toLowerCase().includes(lower)) {
          firstLine = i + 1;
          snippet = lines[i].trim().slice(0, 80);
          break;
        }
      }
      if (nameMatch || firstLine > 0) {
        hits.push({ nodeId: node.id, name: node.name, path, firstMatchLine: firstLine, snippet });
      }
    }
    this.searchResults.set(hits);
    if (sync) this.syncUrl();
  }

  openHit(hit: SearchHit): void {
    this.openFile(hit.nodeId);
    this.panel.set(null);
    this.syncUrl();
  }

  restoreRevision(rev: Revision): void {
    this.openFile(rev.nodeId);
    this.setContent(rev.nodeId, rev.content);
    this.dirtyIds.update((d) => (d.includes(rev.nodeId) ? d : [...d, rev.nodeId]));
    this.activeRevId.set(rev.id);
    this.saveActive();
  }

  previewRevision(rev: Revision): void {
    this.activeRevId.set(rev.id);
    this.syncUrl();
  }

  // ---- Tree operations ----
  createNode(payload: CreatePayload): void {
    const label = payload.type === 'folder' ? 'folder' : 'file';
    const name = prompt(`New ${label} name`, payload.type === 'folder' ? 'new-folder' : 'untitled.js');
    if (!name) return;
    const node: TreeNode = {
      id: `n-${Math.round(performance.now())}`,
      workspaceId: this.workspaceId(),
      parentId: payload.parentId,
      type: payload.type,
      name: name.trim(),
      children: payload.type === 'folder' ? [] : undefined,
    };
    this.tree.set(this.insertChild(this.tree(), payload.parentId, node));
    if (payload.type === 'file') {
      this.fileContents.update((f) => [...f, { nodeId: node.id, content: '' }]);
      this.openFile(node.id);
    }
  }

  renameNode(id: string): void {
    const node = this.findNode(this.tree(), id);
    if (!node) return;
    const name = prompt('Rename to', node.name);
    if (!name) return;
    this.tree.set(this.patchNode(this.tree(), id, { name: name.trim() }));
    this.openTabs.update((tabs) => tabs.map((t) => (t.id === id ? { ...t, name: name.trim() } : t)));
  }

  removeNode(id: string): void {
    const node = this.findNode(this.tree(), id);
    if (!node) return;
    if (!confirm(`Delete “${node.name}”${node.type === 'folder' ? ' and everything inside it' : ''}?`)) {
      return;
    }
    const removedIds = this.collectIds(node);
    this.tree.set(this.removeFromTree(this.tree(), id));
    this.fileContents.update((f) => f.filter((c) => !removedIds.has(c.nodeId)));
    this.openTabs.update((tabs) => tabs.filter((t) => !removedIds.has(t.id)));
    if (this.activeId() && removedIds.has(this.activeId()!)) {
      const rest = this.openTabs();
      this.activeId.set(rest.length ? rest[rest.length - 1].id : null);
    }
    this.syncUrl();
  }

  moveNode(payload: MovePayload): void {
    const { nodeId, parentId } = payload;
    if (nodeId === parentId) return;
    const moving = this.findNode(this.tree(), nodeId);
    if (!moving) return;
    // Cycle guard: cannot move a folder into its own descendant.
    if (parentId && this.collectIds(moving).has(parentId)) {
      this.error.set('Cannot move a folder into itself.');
      setTimeout(() => this.error.set(null), 2500);
      return;
    }
    const detached = this.removeFromTree(this.tree(), nodeId);
    const updatedNode: TreeNode = { ...moving, parentId };
    this.tree.set(this.insertChild(detached, parentId, updatedNode));
  }

  // ---- URL sync (deep-linkable state) ----
  private syncUrl(): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: {
        file: this.activeId() || null,
        panel: this.panel() || null,
        q: this.panel() === 'search' && this.searchTerm() ? this.searchTerm() : null,
        rev: this.panel() === 'history' && this.activeRevId() ? this.activeRevId() : null,
      },
      queryParamsHandling: 'merge',
      replaceUrl: true,
    });
  }

  // ---- Tree helpers (pure, immutable) ----
  private findNode(nodes: TreeNode[], id: string): TreeNode | null {
    for (const n of nodes) {
      if (n.id === id) return n;
      if (n.children) {
        const found = this.findNode(n.children, id);
        if (found) return found;
      }
    }
    return null;
  }

  private flatten(nodes: TreeNode[]): TreeNode[] {
    const out: TreeNode[] = [];
    for (const n of nodes) {
      out.push(n);
      if (n.children) out.push(...this.flatten(n.children));
    }
    return out;
  }

  private collectIds(node: TreeNode): Set<string> {
    const ids = new Set<string>([node.id]);
    for (const c of node.children || []) {
      for (const id of this.collectIds(c)) ids.add(id);
    }
    return ids;
  }

  private removeFromTree(nodes: TreeNode[], id: string): TreeNode[] {
    return nodes
      .filter((n) => n.id !== id)
      .map((n) => (n.children ? { ...n, children: this.removeFromTree(n.children, id) } : n));
  }

  private insertChild(nodes: TreeNode[], parentId: string | null, child: TreeNode): TreeNode[] {
    if (parentId === null) {
      return [...nodes, child];
    }
    return nodes.map((n) => {
      if (n.id === parentId) {
        return { ...n, children: [...(n.children || []), child] };
      }
      return n.children ? { ...n, children: this.insertChild(n.children, parentId, child) } : n;
    });
  }

  private patchNode(nodes: TreeNode[], id: string, patch: Partial<TreeNode>): TreeNode[] {
    return nodes.map((n) => {
      if (n.id === id) return { ...n, ...patch };
      return n.children ? { ...n, children: this.patchNode(n.children, id, patch) } : n;
    });
  }

  private setContent(id: string, content: string): void {
    const exists = this.fileContents().some((f) => f.nodeId === id);
    if (exists) {
      this.fileContents.update((f) => f.map((c) => (c.nodeId === id ? { ...c, content } : c)));
    } else {
      this.fileContents.update((f) => [...f, { nodeId: id, content }]);
    }
  }

  private buildPaths(): Map<string, string> {
    const map = new Map<string, string>();
    const walk = (nodes: TreeNode[], prefix: string) => {
      for (const n of nodes) {
        const path = `${prefix}/${n.name}`;
        map.set(n.id, path);
        if (n.children) walk(n.children, path);
      }
    };
    walk(this.tree(), '');
    return map;
  }
}
