import { Component, EventEmitter, Input, Output } from '@angular/core';
import { CommonModule } from '@angular/common';
import { TreeNode } from '../../core/models';

export interface CreatePayload {
  parentId: string | null;
  type: 'file' | 'folder';
}
export interface MovePayload {
  nodeId: string;
  parentId: string | null;
}

/**
 * Recursive file-tree. Renders a workspace's virtual tree with per-node create /
 * rename / delete actions and native HTML5 drag-to-move (dropping a node onto a
 * folder re-parents it via `moveNode`). Standalone components can reference their
 * own selector recursively, so nested folders render `<app-file-tree>` again.
 */
@Component({
  selector: 'app-file-tree',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './file-tree.component.html',
  styleUrl: './file-tree.component.css',
})
export class FileTreeComponent {
  @Input() nodes: TreeNode[] = [];
  @Input() activeId: string | null = null;
  @Input() depth = 0;

  @Output() select = new EventEmitter<string>();
  @Output() createNode = new EventEmitter<CreatePayload>();
  @Output() renameNode = new EventEmitter<string>();
  @Output() removeNode = new EventEmitter<string>();
  @Output() moveNode = new EventEmitter<MovePayload>();

  /** Folders collapsed by id; folders are expanded by default. */
  private readonly collapsed = new Set<string>();
  dragOverId: string | null = null;

  isExpanded(node: TreeNode): boolean {
    return !this.collapsed.has(node.id);
  }
  toggle(node: TreeNode): void {
    if (this.collapsed.has(node.id)) this.collapsed.delete(node.id);
    else this.collapsed.add(node.id);
  }

  iconFor(name: string): string {
    const ext = (name.split('.').pop() || '').toLowerCase();
    const map: Record<string, string> = {
      js: '🟨',
      ts: '🟦',
      json: '🟢',
      html: '🟧',
      css: '🎨',
      md: '📝',
      py: '🐍',
    };
    return map[ext] || '📄';
  }

  // ---- Drag & drop (native HTML5) ----
  onDragStart(event: DragEvent, node: TreeNode): void {
    event.dataTransfer?.setData('text/nodeid', node.id);
    if (event.dataTransfer) event.dataTransfer.effectAllowed = 'move';
  }
  onDragOver(event: DragEvent, node: TreeNode): void {
    if (node.type !== 'folder') return;
    event.preventDefault();
    this.dragOverId = node.id;
    if (event.dataTransfer) event.dataTransfer.dropEffect = 'move';
  }
  onDragLeave(node: TreeNode): void {
    if (this.dragOverId === node.id) this.dragOverId = null;
  }
  onDrop(event: DragEvent, node: TreeNode): void {
    if (node.type !== 'folder') return;
    event.preventDefault();
    const id = event.dataTransfer?.getData('text/nodeid');
    this.dragOverId = null;
    if (id && id !== node.id) {
      this.moveNode.emit({ nodeId: id, parentId: node.id });
    }
  }
}
