import {
  Component,
  EventEmitter,
  Input,
  OnChanges,
  Output,
  SimpleChanges,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

/**
 * CodeDeck code editor.
 *
 * Mockup stand-in for the CodeMirror 6 wrapper described in the plan: a mono
 * font-styled textarea with a one-dark-like theme, extension→language badge, and
 * a Ctrl/Cmd+S save keymap. Emits `(contentChange)` on edit and `(save)` on
 * Ctrl/Cmd+S. Downstream, the ui/service agents swap the textarea for an
 * `EditorView` built in `ngAfterViewInit` while keeping this input/output shape.
 */
@Component({
  selector: 'app-code-editor',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './code-editor.component.html',
  styleUrl: './code-editor.component.css',
})
export class CodeEditorComponent implements OnChanges {
  /** Active node id — a change means "load a different file" (reset the buffer). */
  @Input() fileId: string | null = null;
  @Input() content = '';
  @Input() filename = '';
  @Output() contentChange = new EventEmitter<string>();
  @Output() save = new EventEmitter<void>();

  /** Local editable buffer so keystrokes never fight parent change detection. */
  text = '';

  ngOnChanges(changes: SimpleChanges): void {
    // Reload the buffer only when the file switches (not on every keystroke).
    if (changes['fileId'] || (changes['content'] && this.text === '')) {
      this.text = this.content;
    }
  }

  get language(): string {
    const ext = (this.filename.split('.').pop() || '').toLowerCase();
    const map: Record<string, string> = {
      js: 'JavaScript',
      mjs: 'JavaScript',
      ts: 'TypeScript',
      jsx: 'JavaScript',
      tsx: 'TypeScript',
      html: 'HTML',
      css: 'CSS',
      scss: 'SCSS',
      json: 'JSON',
      md: 'Markdown',
      py: 'Python',
      txt: 'Plain text',
    };
    return map[ext] || 'Plain text';
  }

  get lineCount(): number {
    return this.text ? this.text.split('\n').length : 1;
  }

  get lines(): number[] {
    return Array.from({ length: this.lineCount }, (_, i) => i + 1);
  }

  onInput(value: string): void {
    this.text = value;
    this.contentChange.emit(value);
  }

  onSave(event: Event): void {
    event.preventDefault();
    this.save.emit();
  }
}
