import { Component, EventEmitter, Input, Output } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Revision } from '../../core/models';

/**
 * Revision history panel (`?panel=history`). Shows the most recent revisions for
 * the active file (backend caps at 10). Restoring a revision emits `(restore)`
 * so the editor shell replaces the buffer content and records a new revision.
 */
@Component({
  selector: 'app-revision-history',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './revision-history.component.html',
  styleUrl: './revision-history.component.css',
})
export class RevisionHistoryComponent {
  @Input() revisions: Revision[] = [];
  @Input() fileName: string | null = null;
  @Input() activeRevId: string | null = null;

  @Output() restore = new EventEmitter<Revision>();
  @Output() preview = new EventEmitter<Revision>();
  @Output() closePanel = new EventEmitter<void>();
}
